---@class LBuffExpressData
local LBuffExpressData = LxClass("LBuffExpressData",nil)
-----------------------------------------------------------------
-----------------------------------------------------------------
function LBuffExpressData:LBuffExpressData()

end

function LBuffExpressData:Create(skillExpressId)
    local skillShowEffEf = gModelSkill:GetSkillExpressionRefByRefId(skillExpressId)
    if not skillShowEffEf then
        if LOG_INFO_ENABLED then
            printErrorN("不能存在的 skillExpressId id : "..tostring(skillExpressId))
        end
        return false
    end

    local playEff = skillShowEffEf.playEff
    local playEffectMap = {}

    self._playEffectMap = playEffectMap

    --重新组织 结构，可以方便不需要配置表 就可以自己生成 表演结构
    self._playEffectList = self:ParsePlayEff(playEffectMap,playEff)

    --根据延迟时间排序
    local sortFunc = function (a,b)
        return a.delayTime < b.delayTime
    end
    table.sort(self._playEffectList,sortFunc)


    --预测大概时间，只计算一层嵌套
    self._skillShowTime = self:CalcSkillTime(self._playEffectList)
end

function LBuffExpressData:ParsePlayEff(hadMap,playEffListStr)
    --- 统一由 modelSkill 接管，方便外面调用，修改
    return gModelSkill:ParsePlayEff(hadMap,playEffListStr)
end

function LBuffExpressData:ParseOffset(str)
    if string.isempty(str) then return Vector3.zero end
    local offset = LxDataHelper.ParseVector(str)
    return offset
end

function LBuffExpressData:GetPlayList()
    return self._playEffectList or {}
end

function LBuffExpressData:CalcSkillTime(playeEffList)
    local maxTime = 0
    for k,v in pairs(playeEffList) do
        local max = v.delayTime + v.playTime
        if max > maxTime then
            maxTime = max
        end
    end
    return maxTime
end

function LBuffExpressData:GetConsumeTime()
    return self._skillShowTime
end


return LBuffExpressData